<Stats id="monster-ngoga--stats" atts={[23,20,18,2,13,9]} bab={9} cmb={16} cmd={31} feats={["Improved Bull Rush","Improved Initiative","Improved Iron Will","Iron Will","Rending Claws"]} skills={{"climb":{"b":20},"per":{"b":7},"stl":{"b":7}}} />
