<SpellBlock id="monster-nisid--spells-monster-spellblock-1" sla={{"cl":6,"con":"+10","content":[{"will":true,"content":<><Link to="/spell/charm_animal">charm animal</Link> (DC 15), <Link to="/spell/create_water">create water</Link>, <Link to="/spell/endure_elements">endure elements</Link></>},{"day":3,"content":<><Link to="/spell/detect_thoughts">detect thoughts</Link> (DC 16), <Link to="/spell/entangle">entangle</Link> (DC 15), <Link to="/spell/invisibility">invisibility</Link> (self only)</>},{"day":1,"content":<><Link to="/spell/call_lightning">call lightning</Link> (DC 17), <Link to="/spell/confusion">confusion</Link> (DC 18), <Link to="/spell/gust_of_wind">gust of wind</Link> (DC 16), <Link to="/spell/hallucinatory_terrain">hallucinatory terrain</Link> (DC 18)</>}]}} />
