<Stats id="monster-reaper_grim_reaper--stats" atts={[24,15,0,16,19,29]} bab={21} cmb={24} cmd={50} cmdP="can't be tripped" feats={["Cleave","Combat Casting","Combat Expertise","Combat Reflexes","Critical Focus","Great Cleave",["Greater Weapon Focus"," (scythe)"],["Improved Critical"," (scythe)"],"Improved Disarm","Improved Initiative","Power Attack",["Quicken Spell-Like Ability"," (destruction)"],"Vital Strike",["Weapon Focus"," (scythe)"]]} skills={{"diplo":{"b":37},"dis":{"b":40},"sm":{"b":35},"stl":{"b":29}}} lang={["C","Ce","I",";",[<em>truespeech</em>]]} />
